func ParseConfig(input string) (map[string]interface{}, error) {
	result := make(map[string]interface{})
	lines := strings.Split(input, "\n")
	var section string
	propRe := regexp.MustCompile(`^([a-zA-Z0-9_.]+)\s*=\s*(.*)$`)
	iniRe := regexp.MustCompile(`^([a-zA-Z0-9_]+)\s*:\s*(.*)$`)
	envRe := regexp.MustCompile(`\$\{([^:}]+):-([^}]*)\}`)
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" || strings.HasPrefix(line, "#") { continue }
		if strings.HasPrefix(line, "[") && strings.HasSuffix(line, "]") {
			section = strings.TrimSpace(line[1 : len(line)-1])
			continue
		}
		if m := propRe.FindStringSubmatch(line); m != nil {
			key := m[1]
			raw := strings.TrimSpace(m[2])
			val, _ := parseValue(raw, envRe)
			result[key] = val
			continue
		}
		if section != "" {
			if m := iniRe.FindStringSubmatch(line); m != nil {
				key := section + "." + m[1]
				raw := strings.TrimSpace(m[2])
				val, _ := parseValue(raw, envRe)
				result[key] = val
			}
		}
	}
	return result, nil
}

func parseValue(raw string, envRe *regexp.Regexp) (interface{}, error) {
	s := raw
	if strings.HasPrefix(raw, `"`) && strings.HasSuffix(raw, `"`) { s = raw[1:len(raw)-1] }
	s = envRe.ReplaceAllStringFunc(s, func(match string) string {
		sub := envRe.FindStringSubmatch(match)
		if v := os.Getenv(sub[1]); v != "" { return v }
		return sub[2]
	})
	if strings.HasPrefix(s, "base64:") {
		dec, _ := base64.StdEncoding.DecodeString(s[7:])
		return string(dec), nil
	}
	switch strings.ToLower(s) { case "true": return true, nil; case "false": return false, nil }
	if i, err := strconv.ParseInt(s, 10, 64); err == nil { return i, nil }
	return s, nil
}
